import React from 'react';

/*
 Visualizes the heap as nested lists. No animations.
 data: { n, roots: [rootIds], nodes: [ {id,key,label,parent,children[]} ], min }
*/
export default function HeapView({ data }) {
  const nodeMap = new Map(data.nodes.map(n => [n.id, n]));
  const renderNode = (id) => {
    const node = nodeMap.get(id);
    if (!node) return null;
    return (
      <li key={id} style={{ margin: '6px 0' }}>
        <span style={{ fontWeight: data.min === id ? '700' : '400' }}>
          {node.label} ({node.key})
        </span>
        {node.children && node.children.length > 0 && (
          <ul>
            {node.children.map(cid => renderNode(cid))}
          </ul>
        )}
      </li>
    );
  };

  return (
    <div style={{ marginTop: 16 }}>
      <div><strong>Root list:</strong></div>
      <ul>
        {data.roots.map(rid => renderNode(rid))}
      </ul>
    </div>
  );
}
